let incoming = {};
try {
  incoming = $input.first().json;
} catch (e) {
  incoming = {};
}

const body = incoming.body || incoming.data || incoming || {};

let phone = '';
if (body.key && body.key.remoteJid) {
  phone = body.key.remoteJid;
} else if (body.from) {
  phone = body.from;
}
if (phone) {
  phone = phone.replace('@c.us', '').replace('@s.whatsapp.net', '');
}

let message = '';
if (body.message && body.message.conversation) {
  message = body.message.conversation;
} else if (body.message && body.message.extendedTextMessage) {
  message = body.message.extendedTextMessage.text;
} else if (body.body) {
  message = body.body;
} else if (body.text) {
  message = body.text;
}

let customerName = 'عميل';
if (body.pushName) {
  customerName = body.pushName;
} else if (body.notifyName) {
  customerName = body.notifyName;
}

const chatId = phone ? (phone + '@s.whatsapp.net') : '';

let intent = 'inquiry';
if (message && /حجز|برنامج|رحلة|سفر|عمرة|حج|سياحة|booking|trip|travel/i.test(message)) {
  intent = 'booking';
}

return {
  json: {
    phone: phone || 'UNKNOWN',
    message: message || '',
    customerName: customerName,
    chatId: chatId,
    intent: intent,
    timestamp: new Date().toISOString(),
    isValid: !!(phone && message)
  }
};

const memoryData = $input.first().json;
const parsedMessage = $('2. Message Parser').first().json;

let memoryContext = '';
if (Array.isArray(memoryData) && memoryData.length > 0) {
  memoryContext = memoryData.map((m) => {
    return `• ${m.fact || m.summary || 'N/A'}`;
  }).join('\n');
} else {
  memoryContext = 'لا توجد سجلات سابقة لهذا العميل.';
}

const sessionContext = {
  phone: parsedMessage.phone,
  customerName: parsedMessage.customerName,
  currentMessage: parsedMessage.message,
  intent: parsedMessage.intent,
  chatId: parsedMessage.chatId,
  timestamp: parsedMessage.timestamp,
  memoryContext: memoryContext,
  memoryCount: Array.isArray(memoryData) ? memoryData.length : 0,
  sessionId: `session_${parsedMessage.phone}_${Date.now()}`
};

return { json: sessionContext };

const geminiResponse = $input.first().json;
const sessionData = $('4. Session Memory Manager').first().json;

let aiResponse = '';
let newInsight = '';

try {
  if (geminiResponse.candidates && geminiResponse.candidates[0]) {
    aiResponse = geminiResponse.candidates[0].content.parts[0].text;
  } else {
    throw new Error('No response from Gemini');
  }
} catch (e) {
  aiResponse = 'عذراً حبيبي، حصل مشكلة تقنية بسيطة 😅 ممكن تعيد الرسالة تاني؟';
}

aiResponse = aiResponse.trim();

const travelKeywords = /حجز|رحلة|سفر|برنامج|عمرة|حج|وجهة|ميزانية|تاريخ|أشخاص/i;
if (travelKeywords.test(sessionData.currentMessage)) {
  const words = sessionData.currentMessage.split(' ').slice(0, 10).join(' ');
  newInsight = `استفسار سياحي: ${words}...`;
}

if (sessionData.intent === 'booking') {
  newInsight = `طلب حجز رحلة - ${new Date().toLocaleDateString('ar-EG')}`;
}

return {
  json: {
    phone: sessionData.phone,
    customerName: sessionData.customerName,
    chatId: sessionData.chatId,
    originalMessage: sessionData.currentMessage,
    aiResponse: aiResponse,
    intent: sessionData.intent,
    newInsight: newInsight,
    timestamp: sessionData.timestamp,
    sessionId: sessionData.sessionId
  }
};

const errorData = $input.first().json;
const responseProcessor = $('6. Response Processor').first().json;

let errorType = 'UNKNOWN';
let errorMessage = 'Unknown error';
let statusCode = errorData.statusCode || 0;

if (statusCode === 401) {
  errorType = 'AUTH_FAILED_401';
  errorMessage = 'Evolution API Key rejected';
} else if (statusCode === 500) {
  errorType = 'SERVER_ERROR_500';
  errorMessage = 'Evolution API Server Error';
} else if (statusCode === 404) {
  errorType = 'ENDPOINT_404';
  errorMessage = 'Evolution API endpoint not found';
} else if (statusCode === 0 || !statusCode) {
  errorType = 'CONNECTION_FAILED';
  errorMessage = 'Cannot connect to Evolution API';
}

console.error(`❌ [ERROR] ${errorType}: ${errorMessage}`);

return {
  json: {
    status: 'ERROR',
    errorType: errorType,
    errorMessage: errorMessage,
    statusCode: statusCode,
    phone: responseProcessor.phone,
    timestamp: new Date().toISOString()
  }
};

const responseProcessor = $('6. Response Processor').first().json;
const whatsappResult = $input.first().json;

const log = {
  status: 'SUCCESS',
  timestamp: new Date().toISOString(),
  phone: responseProcessor.phone,
  name: responseProcessor.customerName,
  intent: responseProcessor.intent,
  sent: true
};

console.log('✅ [SUCCESS] Workflow Complete');
console.log(JSON.stringify(log, null, 2));

return { json: log };
